<template>
  <div class="screen-container">
    <div class="screen-scale" :style="scaleStyle">
      <ScreenHeader title="职业技能等级认定实操考试" />
      <main class="screen-body">
        <section class="card card-left">
          <div class="card-title-dark">评价职业</div>
          <div class="card-left-content">
            <div class="left-major">
              <div class="major-job">{{ jobName }} {{ jobLevel }}</div>
            </div>
            <div class="queue-table">
              <div class="queue-row">
                <div class="queue-label waiting">等待叫号</div>
                <div class="queue-users">
                  <div class="queue-users-track" :style="queueTrackStyle('waiting')">
                    <div v-for="(user, idx) in queueRenderUsers('waiting')" :key="`waiting-${idx}`"
                      class="queue-user waiting">
                      {{ user }}
                    </div>
                  </div>
                </div>
              </div>
              <div class="queue-row">
                <div class="queue-label">正在考试</div>
                <div class="queue-users">
                  <div class="queue-users-track" :style="queueTrackStyle('testing')">
                    <div v-for="(user, idx) in queueRenderUsers('testing')" :key="`testing-${idx}`" class="queue-user">
                      {{ user }}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </section>
        <section class="card-right">
          <div class="card-right-item">
            <div class="card-title">考试时间</div>
            <div class="card-content">
              <div class="text-line">{{ examTime }}</div>
            </div>
          </div>
          <div class="card-right-item">
            <div class="card-title">考评老师</div>
            <div class="card-content">
              <div class="text-line">{{ teachers.join(" ") }}</div>
            </div>
          </div>
          <div class="card-right-item">
            <div class="card-title">准考证号</div>
            <div class="card-content exam-ticket">
              <div class="text-line">{{ admissionTicket }}（{{ ticketDesc }}）</div>
            </div>
          </div>
        </section>
      </main>
      <footer class="screen-footer">
        <span class="tip-label">温馨提示：请等待叫号依次参加实操考试，</span>
        <span class="tip-text">若已过号请等待重新叫号</span>
      </footer>
    </div>
  </div>
</template>

<script>
import { getTheoryexamination } from "@/api/screen/screen";
import ScreenHeader from "./screenTop.vue";
export default {
  name: "ScreenIndex3",
  components: {
    ScreenHeader,
  },
  data() {
    return {
      designWidth: 2200,
      designHeight: 1090,
      scale: 1,
      offsetX: 0,
      offsetY: 0,
      refreshTimerId: null,
      refreshIntervalMs: 5000,
      dataRequestSeq: 0,
      isFetchingData: false,
      jobName: "养老护理员",
      jobLevel: "五级",
      examTime: "2026年4月27日 8:00-9:00",
      teachers: ["王建立", "张贤亮", "刘宇"],
      admissionTicket:null,
      ticketDesc: "19位准考证编号",
      waitingUsers: ["王建军", "张晓宇", "马冬梅", '张三', '李四'],
      testingUsers: ["王建军", "张晓宇", "马冬梅"],
      queueRafId: null,
      queueHoldMs: 3500,
      queueMoveMs: 700,
      waitingScrollIndex: 0,
      waitingScrollProgress: 0,
      waitingScrollMode: "",
      waitingScrollPhaseStart: 0,
      testingScrollIndex: 0,
      testingScrollProgress: 0,
      testingScrollMode: "",
      testingScrollPhaseStart: 0,
    };
  },
  computed: {
    scaleStyle() {
      return {
        width: `${this.designWidth}px`,
        height: `${this.designHeight}px`,
        transform: `scale(${this.scale})`,
        left: `${this.offsetX}px`,
        top: `${this.offsetY}px`,
      };
    },
  },
  methods: {
    getData(id) {
      if (this.isFetchingData) return;
      this.isFetchingData = true;
      const requestSeq = ++this.dataRequestSeq;
      getTheoryexamination(id)
        .then((res) => {
          if (requestSeq !== this.dataRequestSeq) return;
          if (res && res.state) {
            const model = res.data || {};
            const keys = [
              "jobName",
              "jobLevel",
              "teachers",
              "admissionTicket",
              "waitingUsers",
              "testingUsers",
            ];

            keys.forEach((key) => {
              if (model[key] !== undefined) this[key] = model[key];
            });

            this.examTime = `${model.endTime} 到 ${model.examTime}`;

            this.waitingScrollIndex = 0;
            this.waitingScrollProgress = 0;
            this.waitingScrollMode = "";
            this.testingScrollIndex = 0;
            this.testingScrollProgress = 0;
            this.testingScrollMode = "";
          }
        })
        .finally(() => {
          if (requestSeq === this.dataRequestSeq) this.isFetchingData = false;
        });
    },
    updateScale() {
      const vw =
        window.innerWidth ||
        document.documentElement.clientWidth ||
        this.designWidth;
      const vh =
        window.innerHeight ||
        document.documentElement.clientHeight ||
        this.designHeight;
      const scaleX = vw / this.designWidth;
      const scaleY = vh / this.designHeight;
      const scale = Math.min(scaleX, scaleY);
      this.scale = scale > 0 ? scale : 1;
      this.offsetX = Math.max(0, (vw - this.designWidth * this.scale) / 2);
      this.offsetY = Math.max(0, (vh - this.designHeight * this.scale) / 2);
    },
    handleResize() {
      this.updateScale();
    },
    queueNeedScroll(type) {
      const users = type === "waiting" ? this.waitingUsers : this.testingUsers;
      return Array.isArray(users) && users.length > 3;
    },
    queueRenderUsers(type) {
      const users = type === "waiting" ? this.waitingUsers : this.testingUsers;
      if (!Array.isArray(users) || !users.length) return ["", "", ""];
      if (!this.queueNeedScroll(type)) {
        const list = users.slice(0, 3);
        while (list.length < 3) list.push("");
        return list;
      }
      const startIndex =
        type === "waiting" ? this.waitingScrollIndex : this.testingScrollIndex;
      const renderUsers = [];
      for (let i = 0; i < 4; i++) {
        renderUsers.push(users[(startIndex + i) % users.length]);
      }
      return renderUsers;
    },
    queueTrackStyle(type) {
      if (!this.queueNeedScroll(type)) {
        return { transform: "translate3d(0, 0, 0)" };
      }
      const progress =
        type === "waiting" ? this.waitingScrollProgress : this.testingScrollProgress;
      return {
        transform: `translate3d(-${(100 / 3) * progress}%, 0, 0)`,
      };
    },
    tickSingleQueue(type, now) {
      const users = type === "waiting" ? this.waitingUsers : this.testingUsers;
      if (!Array.isArray(users) || users.length <= 3) {
        if (type === "waiting") {
          this.waitingScrollIndex = 0;
          this.waitingScrollProgress = 0;
          this.waitingScrollMode = "";
        } else {
          this.testingScrollIndex = 0;
          this.testingScrollProgress = 0;
          this.testingScrollMode = "";
        }
        return;
      }
      const modeKey = `${type}ScrollMode`;
      const phaseKey = `${type}ScrollPhaseStart`;
      const progressKey = `${type}ScrollProgress`;
      const indexKey = `${type}ScrollIndex`;
      if (!this[modeKey]) {
        this[modeKey] = "hold";
        this[phaseKey] = now;
        this[progressKey] = 0;
        return;
      }
      if (this[modeKey] === "hold") {
        if (now - this[phaseKey] >= this.queueHoldMs) {
          this[modeKey] = "move";
          this[phaseKey] = now;
        }
        return;
      }
      const progress = (now - this[phaseKey]) / this.queueMoveMs;
      if (progress >= 1) {
        this[progressKey] = 0;
        this[indexKey] = (this[indexKey] + 1) % users.length;
        this[modeKey] = "hold";
        this[phaseKey] = now;
        return;
      }
      this[progressKey] = Math.max(0, Math.min(1, progress));
    },
    startQueueLoop() {
      this.stopQueueLoop();
      const step = (now) => {
        this.tickSingleQueue("waiting", now);
        this.tickSingleQueue("testing", now);
        this.queueRafId = requestAnimationFrame(step);
      };
      this.queueRafId = requestAnimationFrame(step);
    },
    stopQueueLoop() {
      if (this.queueRafId) {
        cancelAnimationFrame(this.queueRafId);
        this.queueRafId = null;
      }
    },
  },
  mounted() {
    // console.log(this.$route.query);
    const roomid = this.$route.query.id;
    this.getData(roomid); 
    this.refreshTimerId = setInterval(() => {
      this.getData(roomid);
    }, this.refreshIntervalMs);
    this.updateScale();
    this.startQueueLoop();
    window.addEventListener("resize", this.handleResize);
  },
  beforeDestroy() {
    if (this.refreshTimerId) {
      clearInterval(this.refreshTimerId);
      this.refreshTimerId = null;
    }
    this.stopQueueLoop();
    window.removeEventListener("resize", this.handleResize);
  },
};
</script>

<style lang="scss" scoped>
:global(html),
:global(body) {
  overflow: hidden;
}

.screen-container {
  position: fixed;
  inset: 0;
  width: 100vw;
  height: 100vh;
  background: #000000;
  overflow: hidden;
}

.screen-scale {
  position: absolute;
  transform-origin: 0 0;
  background-image: url("../../assets/images/screen/bg.png");
  background-size: cover;
  background-position: center;
  font-family: "Microsoft YaHei", "PingFang SC", sans-serif;
  display: flex;
  flex-direction: column;
}

.screen-body {
  flex: 1;
  display: flex;
  padding: 26px 30px 18px;
  gap: 24px;
  min-height: 0;
}

.card {
  margin-top: 20px;
  width: 1159px;
  height: 831px;
  background: #ffffff;
  border-radius: 20px 20px 20px 20px;
}

.card-title {
  height: 107px;
  background: #d0e6f9;
  border-radius: 20px 20px 0px 0px;
  font-weight: 500;
  font-size: 50px;
  color: #165ac7;
  text-align: center;
  line-height: 107px;
}

.card-title-dark {
  color: #ffffff;
  background: linear-gradient(180deg, #2fafff 0%, #0061c5 100%);
  border-radius: 20px 20px 20px 20px;
  height: 110px;
  text-align: center;
  line-height: 110px;
  margin: 18px 18px 0;
  font-weight: 500;
  font-size: 50px;
}

.major-job {
  font-weight: 700;
  font-size: 122px;
  color: #165ac7;
  letter-spacing: 6px;
  padding: 85px 125px 85px 125px;
}

.card-left-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 0;
}

.left-major {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 90px;
  padding: 10px 44px 10px;
  min-height: 0;
}

.queue-row {
  height: 164px;
  display: flex;
  border-radius: 0px 0px 0px 0px;
}

.waiting {
  background: #d0e6f9;
}

.queue-label {
  width: 300px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 500;
  font-size: 52px;
  color: #1a1a1a;
}

.queue-users {
  flex: 1;
  display: flex;
  overflow: hidden;
}

.queue-users-track {
  display: flex;
  width: 100%;
  flex: 0 0 100%;
  will-change: transform;
}

.queue-user {
  flex: 0 0 calc(100% / 3);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 400;
  font-size: 52px;
  color: #165ac7;
}

.queue-user+.queue-user {
  border-left: 1px solid rgba(26, 82, 182, 0.12);
}

.card-content {
  padding: 25px;
  box-sizing: border-box;
  height: 131px;
  background: #fff;
  border-radius: 0px 0px 20px 20px;
  font-weight: 400;
  font-size: 42px;
  color: #1a1a1a;
}

.exam-ticket {
  height: 210px;
}

.text-line {
  line-height: 1.65;
  font-weight: 400;
  font-size: 35px;
  color: #1a1a1a;
}

.card-left {
  flex: 1;
}

.card-right {
  width: 641px;
}

.card-right-item {
  margin-top: 20px;
}

.screen-footer {
  height: 86px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #0287ff;
  font-size: 48px;
  font-weight: 700;
  line-height: 1;
  letter-spacing: 1px;
}

.tip-label {
  color: #ffffff;
  margin-right: 12px;
}

.tip-text {
  color: #ffe600;
}

.tip-text-main {
  color: #ffffff;
}

.tip-text-warn {
  color: #ffe600;
}
</style>
